"dura-max": "<style>\n.drx{--forest:#2c5740;--forest-2:#21452e;--green:#3f7d54;--cta:#2f9e54;--cta-d:#248445;--sage:#eef5ef;--cream:#fff;--ink:#22332a;--muted:#647067;--radius:14px;font-family:'Inter',-apple-system,system-ui,sans-serif;color:var(--ink);line-height:1.62;font-size:17px;background:var(--cream);max-width:920px;margin:0 auto;border-radius:var(--radius);overflow:hidden;box-shadow:0 18px 50px -28px rgba(33,71,46,.45)}\n.drx *{box-sizing:border-box;margin:0;padding:0}\n.drx h1,.drx h2,.drx h3{font-family:system-ui,sans-serif;line-height:1.16;font-weight:700;color:var(--ink)}\n.drx .wrap{padding:44px 36px}\n@media(max-width:600px){.drx .wrap{padding:28px 18px}}\n.drx .hero{color:#eef5ef;padding:52px 36px 48px;text-align:center;background:linear-gradient(160deg,var(--green) 0%,var(--forest) 55%,var(--forest-2) 100%)}\n.drx .eyebrow{display:inline-block;font-size:11px;font-weight:700;letter-spacing:.18em;text-transform:uppercase;color:rgba(255,255,255,.8);margin-bottom:14px}\n.drx .hero h1{font-size:clamp(24px,5vw,36px);color:#fff;margin:0 0 14px}\n.drx .hero p{font-size:16px;color:rgba(238,245,239,.9);max-width:540px;margin:0 auto 28px}\n.drx a.drx-btn,.drx .drx-btn{display:inline-flex !important;align-items:center;justify-content:center;background:#2f9e54 !important;color:#fff !important;font-weight:700;font-size:16px;padding:16px 34px;border-radius:12px !important;border:none !important;cursor:pointer;text-decoration:none !important;box-shadow:0 12px 26px -12px rgba(47,158,84,.75);transition:transform .16s,box-shadow .16s}\n.drx a.drx-btn:hover{transform:translateY(-2px);background:#248445 !important;color:#fff !important}\n.drx a.drx-btn:visited{color:#fff !important}\n.drx .bgrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:18px;margin:32px 0}\n.drx .bcard{background:var(--sage);border-radius:12px;padding:22px 18px;text-align:center}\n.drx .bcard h3{font-size:15px;font-weight:700;margin-bottom:8px;color:var(--forest)}\n.drx .bcard p{font-size:14px;color:var(--muted);line-height:1.5}\n.drx .sec-title{font-size:22px;font-weight:700;margin-bottom:6px}\n.drx .sec-sub{color:var(--muted);margin-bottom:24px;font-size:15px}\n.drx .ingrs{list-style:none;display:grid;gap:12px}\n.drx .ingrs li{display:flex;gap:14px;align-items:flex-start;padding:16px;background:var(--sage);border-radius:10px;font-size:15px}\n.drx .ingrs li strong{color:var(--forest);display:block;font-size:14px;margin-bottom:3px}\n.drx .steps{display:grid;gap:14px;margin-top:20px}\n.drx .step{display:flex;gap:14px;align-items:flex-start;padding:18px;background:var(--sage);border-radius:12px}\n.drx .snum{flex-shrink:0;width:34px;height:34px;background:var(--green);color:#fff;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:14px}\n.drx .stxt strong{display:block;font-size:15px;font-weight:700;margin-bottom:3px;color:var(--forest)}\n.drx .stxt p{font-size:14px;color:var(--muted);margin:0}\n.drx .cta-block{background:linear-gradient(160deg,var(--green) 0%,var(--forest-2) 100%);color:#fff;padding:48px 32px;text-align:center;margin-top:44px;border-radius:14px}\n.drx .cta-block h2{color:#fff;font-size:clamp(20px,4vw,28px);margin-bottom:12px}\n.drx .cta-block p{color:rgba(255,255,255,.85);margin-bottom:26px;font-size:16px;max-width:500px;margin-left:auto;margin-right:auto}\n.drx .badges{display:flex;flex-wrap:wrap;gap:12px;justify-content:center;margin-top:18px;font-size:13px;font-weight:600;color:rgba(255,255,255,.8)}\n.drx .compliance{background:#f5faf6;border:1px solid #dce8df;border-radius:10px;padding:14px 18px;font-size:12px;color:#647067;line-height:1.6;margin-top:22px}\n.drx .compliance strong{color:#22332a}\n</style><div class=\"drx\">\n<div class=\"hero\">\n  <div class=\"eyebrow\">ARMAZEM NATURAL</div>\n  <h1>Disposicao e vitalidade masculina com a natureza</h1>\n  <p>Formula masculina com ativos naturais que apoia a energia, o desempenho fisico e o bem-estar do homem ativo.</p>\n  <a href=\"#\" class=\"drx-btn\">Quero mais disposicao</a>\n</div>\n<div class=\"wrap\">\n  <h2 class=\"sec-title\">Por que funciona</h2>\n  <p class=\"sec-sub\">Formulacao com ativos naturais selecionados</p>\n  <div class=\"bgrid\">\n    <div class=\"bcard\"><h3>Mais Energia</h3><p>Ingredientes que auxiliam na producao de energia e na reducao do cansaco fisico e mental.</p></div><div class=\"bcard\"><h3>Desempenho Fisico</h3><p>Ativos classicos do esporte natural para quem quer ir alem nos treinos e no dia a dia.</p></div><div class=\"bcard\"><h3>Bem-estar Masculino</h3><p>Formula pensada especificamente para as necessidades do homem moderno.</p></div>\n  </div>\n  <h2 class=\"sec-title\" style=\"margin-top:40px\">Ingredientes principais</h2>\n  <p class=\"sec-sub\">Ativos naturais de alta qualidade</p>\n  <ul class=\"ingrs\">\n    <li><div><strong>Maca Peruana</strong>Raiz andina usada por guerreiros incas por sua associacao com energia e resistencia fisica. Rica em aminoacidos.</div></li><li><div><strong>Tribulus Terrestris</strong>Planta amplamente estudada em universidades de varios continentes pelo suporte a vitalidade masculina.</div></li><li><div><strong>Zinco</strong>Mineral essencial para o funcionamento hormonal masculino, o sistema imune e a saude reprodutiva.</div></li>\n  </ul>\n  <h2 class=\"sec-title\" style=\"margin-top:40px\">Como usar</h2>\n  <p class=\"sec-sub\">Simples de incorporar na sua rotina</p>\n  <div class=\"steps\">\n    <div class=\"step\"><div class=\"snum\">1</div><div class=\"stxt\"><strong>Tome pela manha</strong><p>Consuma no cafe da manha para aproveitar o pico de energia ao longo do dia.</p></div></div><div class=\"step\"><div class=\"snum\">2</div><div class=\"stxt\"><strong>Associe aos treinos</strong><p>O suplemento tem maior efeito perceptivel quando combinado com atividade fisica regular.</p></div></div><div class=\"step\"><div class=\"snum\">3</div><div class=\"stxt\"><strong>Mantenha por 90 dias</strong><p>O ciclo completo recomendado e de 3 meses para consolidar os beneficios.</p></div></div>\n  </div>\n  <div class=\"cta-block\">\n    <h2>Sua melhor versao comeca agora</h2>\n    <p>Formula masculina com frete gratis e 30 dias de garantia incondicional.</p>\n    <a href=\"#\" class=\"drx-btn\">Quero mais disposicao</a>\n    <div class=\"badges\"><span>30 dias de garantia</span><span>Frete gratis</span><span>Pagamento seguro</span></div>\n  </div>\n  <div class=\"compliance\"><p><strong>Informacoes importantes:</strong> Este produto e um suplemento alimentar. <strong>Nao e um medicamento</strong> e nao se destina a diagnosticar, tratar, curar ou prevenir qualquer doenca. Resultados podem variar. Consulte um profissional de saude.</p></div>\n</div>\n</div>"
,
